import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the formula for the area of a circle?", a: "The area of a circle is A = pi x r^2, where r is the radius. Square the radius, then multiply by pi." },
  { q: "How do you calculate circumference?", a: "Circumference is the distance around a circle. Use C = 2 x pi x r or C = pi x d, where r is radius and d is diameter." },
  { q: "What is the relationship between radius and diameter?", a: "The diameter is twice the radius, and the radius is half the diameter. The formulas are d = 2r and r = d / 2." },
  { q: "How do you find the radius from the area?", a: "Start with A = pi x r^2, divide the area by pi, then take the square root. The formula is r = sqrt(A / pi)." },
  { q: "What is pi and why is it used in circle calculations?", a: "Pi is the constant ratio between a circle's circumference and diameter. It appears in circle formulas because every circle keeps that same ratio." },
];

type InputType = "radius" | "diameter" | "circumference" | "area";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";

export default function CircleCalculator() {
  const [inputType, setInputType] = useState<InputType>("radius");
  const [value, setValue] = useState(5);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    const v = Math.max(0, value);
    const radius = inputType === "radius" ? v : inputType === "diameter" ? v / 2 : inputType === "circumference" ? v / (2 * Math.PI) : Math.sqrt(v / Math.PI);
    const diameter = radius * 2;
    const circumference = 2 * Math.PI * radius;
    const area = Math.PI * radius * radius;
    const step = inputType === "radius" ? `Given r = ${v}. d = 2r = ${fmt(diameter)}, C = 2pir = ${fmt(circumference)}, A = pir- = ${fmt(area)}.`
      : inputType === "diameter" ? `Given d = ${v}. r = d / 2 = ${fmt(radius)}, C = pid = ${fmt(circumference)}, A = pir- = ${fmt(area)}.`
      : inputType === "circumference" ? `Given C = ${v}. r = C / (2pi) = ${fmt(radius)}, d = 2r = ${fmt(diameter)}, A = pir- = ${fmt(area)}.`
      : `Given A = ${v}. r = sqrt(A / pi) = ${fmt(radius)}, d = 2r = ${fmt(diameter)}, C = 2pir = ${fmt(circumference)}.`;
    return { radius, diameter, circumference, area, step };
  }, [inputType, value]);

  return (
    <>
      <SEOHead title="Free Circle Calculator Online - Calculate Radius Diameter Area and Circumference Instantly | CalcHive" description="Free online circle calculator. Calculate radius, diameter, area and circumference of any circle from a single input instantly. 100% free for students and everyone, no signup required." canonical="/circle-calculator" keywords="free circle calculator, circle area calculator free online, circumference calculator free, radius to diameter calculator free, circle geometry calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Circle Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free circle calculator to find radius, diameter, circumference, and area from one circle measurement.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label htmlFor="circle-input-type" className="text-sm font-semibold text-foreground block mb-2">Known value</label><select id="circle-input-type" value={inputType} onChange={(event) => setInputType(event.target.value as InputType)} className={inputClass}><option value="radius">Radius</option><option value="diameter">Diameter</option><option value="circumference">Circumference</option><option value="area">Area</option></select></div>
            <div><label htmlFor="circle-value" className="text-sm font-semibold text-foreground block mb-2">Value</label><input id="circle-value" type="number" min="0" inputMode="decimal" value={value} onChange={(event) => setValue(Number(event.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${inputType}-${value}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Area</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-circle">{fmt(result.area)}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["Radius", result.radius], ["Diameter", result.diameter], ["Circumference", result.circumference]].map(([label, val]) => <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground font-medium">{label}</p><p className="text-lg font-extrabold text-foreground">{fmt(val as number)}</p></div>)}</div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate All Circle Properties for Free</h2><p className="text-muted-foreground leading-relaxed">Enter radius, diameter, circumference, or area and this circle geometry calculator free tool converts it into every other circle property.</p>
          <h2 className="text-2xl font-bold text-foreground">Circle Formulas for Radius Diameter Area and Circumference</h2><p className="text-muted-foreground leading-relaxed">The main formulas are d = 2r, C = 2pir, C = pid, A = pir- and r = sqrt(A / pi).</p>
          <h2 className="text-2xl font-bold text-foreground">Free Geometry Circle Tool for Students and Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this circumference calculator free and radius to diameter calculator free for geometry homework, design, and measurement checks.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/circle-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


